PTX_KERNELS = {
    "mish_tail": PTXKernelSpec(
        entry="mish_tail",
        grid=lambda x, add_value, scale, n: ((int((n + 255) // 256), 1, 1)),
        block=(256, 1, 1),
        arg_types=("tensor", "float32", "float32", "uint32"),
    ),
}


class ModelNew(nn.Module):
    def __init__(
        self,
        in_channels,
        out_channels,
        kernel_size,
        stride,
        padding,
        output_padding,
        add_value,
        scale,
    ):
        super().__init__()
        seed = torch.initial_seed()
        torch.manual_seed(seed)
        self.conv_transpose = nn.ConvTranspose2d(
            in_channels,
            out_channels,
            kernel_size,
            stride=stride,
            padding=padding,
            output_padding=output_padding,
        )
        self.add_value = float(add_value)
        self.scale = float(scale)
        self.runner = PTXModuleRunner(PTX_SOURCES, PTX_KERNELS)

    def forward(self, x):
        x = self.conv_transpose(x)
        self.runner.launch("mish_tail", x, self.add_value, self.scale, x.numel())
        return x
